const seen = new Set();
const filtered = [];

for (const item of items) {
  const content = item.json.content || '';
  const title = item.json.title || '';
  const description = item.json.description || '';

  // Garbage filter - cookie consent articles hatao
  if (content.includes("If you click")) continue;
  if (content.includes("IAB Transparency")) continue;
  if (content.includes("Accept all")) continue;
  if (title.trim() === '') continue;

  // Duplicates hatao title ke basis pe
  if (seen.has(title)) continue;
  seen.add(title);

  // Sirf title + description rakho
  filtered.push({
    json: {
      summary: `${title}. ${description}`
    }
  });
}

return filtered;

for (const item of items) {
  let text = item.json.text || item.json.output || '';

  text = text.replace(/\\n/g, '').replace(/\n/g, '');

  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      const parsed = JSON.parse(match[0]);
      item.json.shortTermSentiment = parsed.shortTermSentiment;
      item.json.longTermSentiment = parsed.longTermSentiment;
    } catch(e) {
      item.json.error = 'parse failed';
    }
  }
}

return items;
